          type: 'message',
          role: 'user',
          content: [{ type: 'text', text: 'Hello from user' }],
        },
      }),
      JSON.stringify({
        type: 'response_item',
        timestamp: '2024-06-01T10:00:10Z',
        payload: {
          type: 'message',
          role: 'assistant',
          content: [{ type: 'text', text: 'Hello from assistant' }],
        },
