  })

  it('parses JSON file with user and model roles', () => {
    const filePath = join(tmpDir, 'session.json')
    const data = {
      sessionId: 'gem-123',
      timestamp: '2024-06-01T10:00:00Z',
      cwd: '/home/user/proj',
      branch: 'dev',
      turns: [
        { role: 'user', text: 'User message', timestamp: '2024-06-01T10:00:00Z' },
