    const payload = makeManifest({ title: 'new', imported_at: '2024-06-15T13:00:00Z' })
    const result = preserveExistingImportTimestamp(existing, payload)
    expect(result.imported_at).toBe('2024-06-15T13:00:00Z')
  })
